sql:
SELECT type_name, description
FROM sensor_types
ORDER BY type_name;

SELECT cd.*, s.sensor_name 
FROM climate_data cd 
JOIN sensors s ON cd.sensor_id = s.sensor_id;

SELECT COUNT(DISTINCT sensor_id) 
FROM sensors 
WHERE status = 'active' AND sensor_type = 'temperature';

external_knowledge:
- "climate guardians" refers to sensors used for collecting environmental data;
- "recent whispers" represent the recent data collected, including the average temperature and humidity from the latest timestamp;
- "tale" refers to the data quality flag indicating the reliability of the data;
- "mathematical magic" refers to the ACOSH function used to convert the average temperature into a special code or hash;
- "order of their names" means the final result is sorted alphabetically by sensor name.
